code = """import json

# Check the full business data
business_data_file = locals()['var_functions.query_db:20']
if isinstance(business_data_file, str) and business_data_file.endswith('.json'):
    with open(business_data_file, 'r') as f:
        business_data = json.load(f)
else:
    business_data = business_data_file

print(f"Total businesses retrieved: {len(business_data)}")
print(f"First few business IDs: {[biz['business_id'] for biz in business_data[:3]]}")

# Count how many accept credit cards
credit_card_accepting = []
for biz in business_data:
    accepts_credit = False
    if biz.get('attributes') and biz['attributes'] != 'None' and biz['attributes'] != 'None':
        attrs = biz['attributes']
        if isinstance(attrs, dict) and 'BusinessAcceptsCreditCards' in attrs:
            accepts_credit = attrs['BusinessAcceptsCreditCards'] == 'True'
    
    if accepts_credit:
        credit_card_accepting.append(biz)

print(f"Businesses accepting credit cards: {len(credit_card_accepting)}")

# Check if we need to get more data
print('__RESULT__:')
print(json.dumps({
    'total_businesses': len(business_data),
    'credit_card_accepting': len(credit_card_accepting),
    'has_more_data': len(business_data) < 100  # Arbitrary threshold to check if we have full dataset
}))"""

